function mudarBackground(){document.addEventListener("DOMContentLoaded",function(){let e=document.getElementById("hero-bg"),t=["../../src/imagens/interestelar2.png","../../src/imagens/interestelar-hero.png","../../src/imagens/interestelar3.png"],n=0;setInterval(()=>{e.style.opacity=0,setTimeout(()=>{n=(n+1)%t.length,e.style.backgroundImage=`url(${t[n]})`,e.style.opacity=1},1500)},5e3)})}export{mudarBackground};